def gen_topic_question(level, topic):
    templates = [
        f"You are testing a target and notice {topic}. What should you test first?",
        f"A bug bounty hunter discovers {topic} during reconnaissance of a target. What is the most likely impact?",
        f"How does {topic} relate to web application security in a bug bounty context?",
        f"While performing a penetration test, you encounter {topic}. What technique should you use to investigate further?",
        f"What is the most common security issue associated with {topic} in modern web applications?",
    ]
    q = random.choice(templates)
    
    wrong = [
        f"It is not relevant to security testing",
        f"All modern frameworks prevent this automatically",
        f"This only affects legacy applications",
        f"It requires physical access to the server",
        f"Browsers prevent this type of attack",
        f"This cannot be exploited in practice",
        f"It is only a client-side concern",
        f"Firewalls block all related attacks",
        f"This is only relevant to mobile applications",
        f"It is automatically detected by WAFs",
    ]
    
    correct = f"{topic} is significant in bug bounty because it often leads to {['information disclosure', 'privilege escalation', 'account takeover', 'data exposure', 'remote code execution', 'access control bypass'][random.randint(0, 5)]} if not properly secured."
    
    opts = random.sample(wrong, 3)
    ci = random.randint(0, 3)
    opts.insert(ci, correct)
    
    exp = f"Understanding {topic} helps identify critical vulnerabilities. In bug bounty hunting, proper testing of {topic} can uncover high-severity issues."
    
    return {"q": q, "o": opts, "a": ci, "e": exp}

random.seed(42)
for level in range(7, 31):
    if level not in QUESTIONS_DATA:
        topics = TOPIC_KEYWORDS.get(level, [f"Level {level} concepts"])
        questions = []
        used = set()
        for topic in topics:
            if len(questions) >= 15:
                break
            q = gen_topic_question(level, topic)
            if q["q"] in used:
                continue
            used.add(q["q"])
            questions.append(q)
        
        # Fill remaining
        while len(questions) < 15:
            topic = random.choice(topics)
            q = gen_topic_question(level, topic)
            if q["q"] in used:
                continue
            used.add(q["q"])
            questions.append(q)
        
        QUESTIONS_DATA[level] = questions[:15]


def escape(s):
    return s.replace("\\", "\\\\").replace('"', '\\"').replace("\n", "\\n")

