                opts_repr = "[" + ", ".join(f'"{escape(o)}"' for o in q["o"]) + "]"
                f.write(f'        {{"id": {i+1}, "question": "{escape(q["q"])}", "options": {opts_repr}, "correct": {q["a"]}, "explanation": "{escape(q["e"])}"}},\n')
